#!/usr/bin/env python3
import os, json, urllib.request, base64, sys

server = "https://jaeyoonsworkspace-23358853.atlassian.net"
login = "jaeyoonbae99@gmail.com"
token = os.environ["JIRA_API_TOKEN"]
creds = base64.b64encode(f"{login}:{token}".encode()).decode()
headers = {"Authorization": f"Basic {creds}", "Content-Type": "application/json"}

def api(method, path, body=None):
    url = f"{server}/rest/api/2{path}"
    data = json.dumps(body).encode() if body else None
    req = urllib.request.Request(url, data=data, headers=headers, method=method)
    try:
        with urllib.request.urlopen(req) as r:
            return json.load(r)
    except urllib.error.HTTPError as e:
        print(f"HTTP {e.code}: {e.read().decode()}", file=sys.stderr)
        raise

# Step 1: get project issue types to find Sub-task ID
meta = api("GET", "/issue/createmeta?projectKeys=KAN&expand=projects.issuetypes")
project = meta["projects"][0]
print("Available issue types:")
for it in project["issuetypes"]:
    print(f"  id={it['id']} name={it['name']} subtask={it.get('subtask', False)}")

# Find Sub-task type ID
subtask_id = None
for it in project["issuetypes"]:
    if it.get("subtask") or it["name"].lower() in ("sub-task", "subtask"):
        subtask_id = it["id"]
        break

if not subtask_id:
    print("No Sub-task type found. Using Task type instead.")
    for it in project["issuetypes"]:
        if it["name"].lower() == "task":
            subtask_id = it["id"]
            break

print(f"\nUsing issue type ID: {subtask_id}")

with open(".jira/kan51-sub1-desc.md") as f:
    sub1_body = f.read()
with open(".jira/kan51-sub2-desc.md") as f:
    sub2_body = f.read()

sub1 = api("POST", "/issue", {
    "fields": {
        "project": {"key": "KAN"},
        "issuetype": {"id": subtask_id},
        "parent": {"key": "KAN-51"},
        "summary": "FE: PostHog initialization and event tracking",
        "description": sub1_body,
        "priority": {"name": "Medium"}
    }
})
print(f"\nCreated sub-task 1: {sub1['key']} — FE: PostHog initialization and event tracking")

sub2 = api("POST", "/issue", {
    "fields": {
        "project": {"key": "KAN"},
        "issuetype": {"id": subtask_id},
        "parent": {"key": "KAN-51"},
        "summary": "BE: PostHog api_call interceptor and docs",
        "description": sub2_body,
        "priority": {"name": "Medium"}
    }
})
print(f"Created sub-task 2: {sub2['key']} — BE: PostHog api_call interceptor and docs")

